/**
 * Simple normaliser – replace back‑slashes with forward slashes and trim
 * duplicate separators.
 */
QString AgentHotPatcher::normalizePathInContent(const QString& content,
                                               const QString& invalidPath)
{
    QString normalized = invalidPath;
    normalized.replace('\\', '/');
    normalized.replace(QRegularExpression(R"(/+)"), "/");
    return normalized;
}

/**
 * Very naive “is this a valid Unix‑style path?” check.
 */
bool AgentHotPatcher::isValidPath(const QString& path) const
{
    // No spaces and must start with '/' (or a Windows drive like C:\)
    static const QRegularExpression validRx(R"(^([A-Za-z]:\\|/)[^\s]*$)");
    return validRx.match(path).hasMatch();
}

/*=====================================================================
   Correction / patching
  =====================================================================*/

QString AgentHotPatcher::correctHallucination(const HallucinationDetection& detection)
{
    if (detection.hallucinationType == QLatin1String("invalid_path")) {
        QString corrected = detection.expectedContent;
        if (!corrected.isEmpty())
            return corrected;
    }
    // other types could be handled here
    return QString{};
}

/**
 * For now we just try to replace the *first* invalid path we spot. In a
 * production system you would keep a map of “bad → good” strings that
 * evolves at runtime.
 */
NavigationFix AgentHotPatcher::fixNavigationError(const QString& content,
                                                  const QJsonObject& /*context*/)
{
    // Re‑use the same detection logic – if a path hallucination exists we
    // already have a “corrected” version in `detectPathHallucination`.
    HallucinationDetection d = detectPathHallucination(content);
    if (d.detectionId.isEmpty()) return NavigationFix{};

    NavigationFix fix;
    fix.incorrectPath  = d.detectedContent;
    fix.correctPath    = d.expectedContent;
    fix.reasoning      = QStringLiteral("Normalized invalid path");
    fix.effectiveness  = 0.9;
    return fix;
}

/**
 * Apply behaviour patches that have been registered via
 * `createBehaviorPatch()`.  The implementation below simply scans the
 * output for the patch’s `condition` (a substring) and, if found,
 * prepends the `action`.  Real‑world use‑cases could be “force a
 * safety‑warning”, “strip code snippets”, ….
 */
QString AgentHotPatcher::applyBehaviorPatches(const QString& output)
{
    QMutexLocker locker(&m_mutex);
    QString patched = output;
    for (const BehaviorPatch& p : m_behaviorPatches) {
        if (!p.enabled) continue;
        if (patched.contains(p.condition, Qt::CaseInsensitive)) {
            // Example: prepend an explanatory line
            patched.prepend(p.action + QLatin1Char('\n'));
            emit behaviorPatchApplied(p);
        }
    }
    return patched;
}

/*=====================================================================
   Registration API (used by the bridge)
  =====================================================================*/

void AgentHotPatcher::registerCorrectionPattern(const HallucinationDetection& pattern)
{
    QMutexLocker locker(&m_mutex);
    m_correctionPatterns.push_back(pattern);
    if (m_debugLogging) qInfo() << "[HotPatcher] Registered correction pattern"
                                << pattern.detectionId;
}

void AgentHotPatcher::registerNavigationFix(const NavigationFix& fix)
{
    QMutexLocker locker(&m_mutex);
    m_navigationPatterns.push_back(fix);
    if (m_debugLogging) qInfo() << "[HotPatcher] Registered navigation fix"
                                << fix.incorrectPath;
}

void AgentHotPatcher::createBehaviorPatch(const BehaviorPatch& patch)
{
    QMutexLocker locker(&m_mutex);
    m_behaviorPatches.push_back(patch);
    if (m_debugLogging) qInfo() << "[HotPatcher] Created behavior patch"
                                << patch.patchId;
}

