AgentHotPatcher::AgentHotPatcher(QObject* parent)
    : QObject(parent)
{
    // Register meta‑types **once** for the whole process.
    qRegisterMetaType<HallucinationDetection>("HallucinationDetection");
    qRegisterMetaType<NavigationFix>("NavigationFix");
    qRegisterMetaType<BehaviorPatch>("BehaviorPatch");
}

AgentHotPatcher::~AgentHotPatcher() = default;

/*=====================================================================
   PUBLIC API
  =====================================================================*/

void AgentHotPatcher::initialize(const QString& ggufLoaderPath, int /*flags*/)
{
    Q_UNUSED(ggufLoaderPath);
    // In a real system you would start a child process that talks to the
    // GGUF loader, load ML models, etc. Here we only mark the component as
    // ready.
    m_hotPatchingEnabled = true;
    if (m_debugLogging) qInfo() << "[HotPatcher] Initialized, ready.";
}

/**
 * Core entry‑point – called by the GGUF‑proxy for every model response.
 * The method runs **quickly**: it only scans the string for known patterns,
 * possibly calls `detectHallucination()` and then patches the output.
 */
QString AgentHotPatcher::interceptModelOutput(const QString& modelOutput,
                                             const QJsonObject& context)
{
    Q_UNUSED(context);

    if (!m_hotPatchingEnabled) return modelOutput;   // pass‑through

    // 1️⃣  Detect a hallucination (if any)
    HallucinationDetection detection = detectHallucination(modelOutput, context);
    if (!detection.detectionId.isEmpty()) {          // a detection happened
        ++m_totalHallucinationsDetected;
        emit hallucinationDetected(detection);

        // 2️⃣  Attempt to fix it
        QString corrected = correctHallucination(detection);
        if (!corrected.isEmpty() && corrected != modelOutput) {
            ++m_hallucinationsCorrected;
            emit hallucinationCorrected(detection); // re‑use same struct (you may add a field)
            return corrected;
        }
    }

    // 3️⃣  Navigation‑error fix (run after hallucination because a bad path
    //     often looks like a hallucination)
    NavigationFix navFix = fixNavigationError(modelOutput, context);
    if (!navFix.incorrectPath.isEmpty()) {
        ++m_navigationFixesApplied;
        emit navigationErrorFixed(navFix);
        // Simple string‑replace – in a real system you may need a more
        // sophisticated normaliser.
        QString fixed = modelOutput;
        fixed.replace(navFix.incorrectPath, navFix.correctPath);
        return fixed;
    }

    // 4️⃣  Behavioural patches (e.g. add a safety disclaimer)
    return applyBehaviorPatches(modelOutput);
}

/*=====================================================================
   Detection / correction helpers
  =====================================================================*/

HallucinationDetection AgentHotPatcher::detectHallucination(const QString& content,
                                                            const QJsonObject& /*context*/)
{
    // The real implementation would run a classifier or pattern matcher.
    // Below is a *very* simple rule‑based example.

    // ----- Path‑related hallucination -----
    HallucinationDetection pd = detectPathHallucination(content);
    if (!pd.detectionId.isEmpty()) return pd;

    // ----- Logic contradiction -----
    HallucinationDetection lc = detectLogicContradiction(content);
    if (!lc.detectionId.isEmpty()) return lc;

    // ----- Incomplete reasoning -----
    HallucinationDetection ir = detectIncompleteReasoning(content);
    if (!ir.detectionId.isEmpty()) return ir;

    // Nothing found → return an empty detection (id stays empty)
    return HallucinationDetection{};
}

/**
 * Very naive path hallucination detector – looks for strings that look
 * like file‑system paths but fail a simple validity check.
 */
HallucinationDetection AgentHotPatcher::detectPathHallucination(const QString& content)
{
    // Example: detect strings that start with '/' or drive letters but contain
    // illegal characters (e.g. spaces in a Unix path).
    static const QRegularExpression pathRx(R"(([/\\][\w\-.\\\/]+))");
    QRegularExpressionMatch match = pathRx.match(content);
    if (!match.hasMatch()) return HallucinationDetection{};

    QString candidate = match.captured(0);
    if (isValidPath(candidate)) return HallucinationDetection{};   // actually fine

    HallucinationDetection d;
    d.detectionId        = QUuid::createUuid().toString();
    d.hallucinationType = QStringLiteral("invalid_path");
    d.confidence        = 0.85;
    d.detectedContent   = candidate;
    d.expectedContent   = normalizePathInContent(content, candidate);
    d.correctionStrategy = QStringLiteral("normalize_path");
    d.detectedAt        = QDateTime::currentDateTimeUtc();
    return d;
}

